import LocalAuthentication
import UIKit

class BiometricAuthenticationManager {
    static let shared = BiometricAuthenticationManager()
    
    private let context = LAContext()
    private let userDefaults = UserDefaults.standard
    private let biometricAuthEnabledKey = "biometricAuthEnabled"
    private let userAuthenticatedKey = "userAuthenticated"
    
    private init() {}
    
    func isBiometricAuthenticationAvailable() -> Bool {
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func getBiometricType() -> LABiometryType {
        let context = LAContext()
        var error: NSError?
        context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
        return context.biometryType
    }
    
    func isBiometricAuthEnabled() -> Bool {
        return userDefaults.bool(forKey: biometricAuthEnabledKey)
    }
    
    func setBiometricAuthEnabled(_ enabled: Bool) {
        userDefaults.set(enabled, forKey: biometricAuthEnabledKey)
    }
    
    func isUserAuthenticated() -> Bool {
        return userDefaults.bool(forKey: userAuthenticatedKey)
    }
    
    func setUserAuthenticated(_ authenticated: Bool) {
        userDefaults.set(authenticated, forKey: userAuthenticatedKey)
    }
    
    func authenticateWithBiometrics(reason: String = "Authenticate to access your account", completion: @escaping (Bool, Error?) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Enter Password"
        context.localizedFallbackTitle = "Use Password"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, error)
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authenticationError in
            DispatchQueue.main.async {
                if success {
                    self.setUserAuthenticated(true)
                    completion(true, nil)
                } else {
                    completion(false, authenticationError)
                }
            }
        }
    }
    
    func logout() {
        setUserAuthenticated(false)
    }
}

